"""
A simple wrapper for qt uic tool.
Script for qt_library.gni.
"""

import argparse
import os.path
import subprocess
import sys

def StripUIFileExtension(filename):
  if not filename.endswith(".ui"):
    raise RuntimeError("Invalid ui filename extension: "
                       "{0} .".format(filename))
  return filename.rsplit(".", 1)[0]


def main(argv):
  parser = argparse.ArgumentParser()
  parser.add_argument("--uic",
                      help="Relative path to uic compiler.")

  parser.add_argument("--header-out-dir",
                      help="Output directory for generated header files.")
  parser.add_argument("--no-protection",
                      help="disable header protection.")
  parser.add_argument("--no-implicit-includes",
                      help="disable generation of #include-directives for forms generated by uic3.")

  parser.add_argument("ui_files", nargs="+",
                      help="Input ui file(s).")

  options = parser.parse_args()

  uic_cmd = [os.path.realpath(options.uic)]

  ui_files = options.ui_files

  out_dir = options.header_out_dir

  if options.no_protection:
    uic_cmd += ["-p"]

  if options.no_implicit_includes:
    uic_cmd += ["-n"]

  for filename in header_files:
    stripped_name = StripUIFileExtension(filename)
    h_file = os.path.join(cc_out_dir, stripped_name + ".h")
    uic_cmd += ["-o", h_file]
    uic_cmd += [filename]
    ret = subprocess.call(uic_cmd)
    if ret != 0:
      if ret <= -100:
        # Windows error codes such as 0xC0000005 and 0xC0000409 are much easier to
        # recognize and differentiate in hex. In order to print them as unsigned
        # hex we need to add 4 Gig to them.
        error_number = "0x%08X" % (ret + (1 << 32))
      else:
        error_number = "%d" % ret
      raise RuntimeError("uic has returned non-zero status: "
                         "{0}".format(error_number))


if __name__ == "__main__":
  try:
    main(sys.argv)
  except RuntimeError as e:
    print(e, file=sys.stderr)
    sys.exit(1)
